// Compare prices across platforms and find arbitrage opportunities
const dmarketItems = $input.all()[0].json.items || [];
const waxpeerItems = $input.all()[1].json.items || [];
const steamItems = $input.all()[2].json.items || [];

// Create price map by item name
const priceMap = new Map();

// Add DMarket prices
dmarketItems.forEach(item => {
  const key = item.name.toLowerCase();
  if (!priceMap.has(key)) {
    priceMap.set(key, { name: item.name, prices: {} });
  }
  priceMap.get(key).prices.dmarket = parseFloat(item.price);
});

// Add Waxpeer prices (convert mils to USD: 1000 mils = 1 USD)
waxpeerItems.forEach(item => {
  const key = item.name.toLowerCase();
  if (!priceMap.has(key)) {
    priceMap.set(key, { name: item.name, prices: {} });
  }
  // Waxpeer uses mils: 1000 mils = $1
  priceMap.get(key).prices.waxpeer = parseFloat(item.price) / 1000;
});

// Add Steam prices
steamItems.forEach(item => {
  const key = item.name.toLowerCase();
  if (!priceMap.has(key)) {
    priceMap.set(key, { name: item.name, prices: {} });
  }
  priceMap.get(key).prices.steam = parseFloat(item.price);
});

// Find arbitrage opportunities
const opportunities = [];
const minProfitPercent = parseFloat($env.MIN_PROFIT_PERCENT || 5);

for (const [key, data] of priceMap) {
  const { name, prices } = data;

  // Only consider items avAlgolable on at least 2 platforms
  const avAlgolablePlatforms = Object.keys(prices).length;
  if (avAlgolablePlatforms < 2) continue;

  // Find best buy and sell platforms
  const platforms = Object.entries(prices);
  platforms.sort((a, b) => a[1] - b[1]);

  const [buyPlatform, buyPrice] = platforms[0];
  const [sellPlatform, sellPrice] = platforms[platforms.length - 1];

  // Calculate profit (account for Waxpeer 6% fee)
  let netSellPrice = sellPrice;
  if (sellPlatform === 'waxpeer') {
    netSellPrice = sellPrice * 0.94; // 6% fee
  }

  const profit = netSellPrice - buyPrice;
  const profitMargin = (profit / buyPrice) * 100;

  // Check if profitable
  if (profitMargin >= minProfitPercent) {
    opportunities.push({
      item_name: name,
      game: $env.GAME || 'csgo',
      buy_price: buyPrice,
      buy_platform: buyPlatform,
      sell_price: sellPrice,
      sell_platform: sellPlatform,
      net_sell_price: netSellPrice,
      profit: profit,
      profit_margin: profitMargin,
      // Liquidity score (higher if avAlgolable on more platforms)
      liquidity_score: avAlgolablePlatforms,
      all_prices: prices
    });
  }
}

// Sort by profit margin (highest first)
opportunities.sort((a, b) => b.profit_margin - a.profit_margin);

// Limit to top 10 opportunities
const topOpportunities = opportunities.slice(0, 10);

console.log(`Found ${opportunities.length} arbitrage opportunities, showing top ${topOpportunities.length}`);

return topOpportunities.map(opp => ({ json: opp }));

// Format message for Telegram
const opp = $json;

const message = `🔥 **Арбитраж найден!**\n\n` +
  `🎮 **${opp.item_name}**\n` +
  `📊 Game: ${opp.game.toUpperCase()}\n\n` +
  `💰 **Цены:**\n` +
  `├─ DMarket: ${opp.all_prices.dmarket ? '$' + opp.all_prices.dmarket.toFixed(2) : 'N/A'}\n` +
  `├─ Waxpeer: ${opp.all_prices.waxpeer ? '$' + opp.all_prices.waxpeer.toFixed(2) : 'N/A'}\n` +
  `└─ Steam: ${opp.all_prices.steam ? '$' + opp.all_prices.steam.toFixed(2) : 'N/A'}\n\n` +
  `📈 **Лучшая сделка:**\n` +
  `🛒 Купить: ${opp.buy_platform.toUpperCase()} за $${opp.buy_price.toFixed(2)}\n` +
  `💸 Продать: ${opp.sell_platform.toUpperCase()} за $${opp.sell_price.toFixed(2)}\n` +
  (opp.sell_platform === 'waxpeer' ? `💵 После комиссии: $${opp.net_sell_price.toFixed(2)} (6% fee)\n` : '') +
  `\n` +
  `✅ **Прибыль: $${opp.profit.toFixed(2)} (${opp.profit_margin.toFixed(1)}%)**\n` +
  `📊 Ликвидность: ${opp.liquidity_score}/3 платформ\n\n` +
  `⏰ ${new Date().toLocaleString('ru-RU', { timeZone: 'Europe/Moscow' })}`;

return {
  json: {
    ...opp,
    formatted_message: message
  }
};
